class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        int[] answer = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int k = queries[i][0];
            int trim = queries[i][1];
            String[] trimmed = new String[nums.length];
            for (int j = 0; j < nums.length; j++) {
                trimmed[j] = nums[j].substring(nums[j].length() - trim);
            }
            Integer[] indices = new Integer[nums.length];
            for (int j = 0; j < nums.length; j++) {
                indices[j] = j;
            }
            Arrays.sort(indices, (a, b) -> {
                if (Integer.parseInt(trimmed[a]) == Integer.parseInt(trimmed[b])) {
                    return a - b;
                } else {
                    return Integer.parseInt(trimmed[a]) - Integer.parseInt(trimmed[b]);
                }
            });
            answer[i] = indices[k - 1];
        }
        return answer;
    }
}
